+    }
+    const state = getState();
+    if (!state.slides) {
+      if (opts?.fallback) clearSlideStrip(hostEl);
+      return;
+    }
+    const slidesByIndex = new Map(state.slides.slides.map((slide) => [slide.index, slide]));
+    const slideTotal = state.slides.slides.length || slidesByIndex.size;
